class TestCryptoPipelineSilenceAlert(unittest.TestCase):
    def test_fires_on_extreme_oversold_and_silence(self):
        stats = {
            "rsi_snapshot": {"BTC/USD": {"today": 14.5}, "ETH/USD": {"today": 19.5}},
            "by_strategy": {"crypto-momentum": {"trades_7d": 0}, "crypto-oversold-bounce": {"trades_7d": 0}},
        }
        fired, reason = heuristic_crypto_pipeline_silence_alert(stats)
        self.assertTrue(fired)
        self.assertIn("CRYPTO-PIPELINE-SILENT", reason)

    def test_no_fire_when_btc_rsi_above_threshold(self):
        stats = {
            "rsi_snapshot": {"BTC/USD": {"today": 21.0}, "ETH/USD": {"today": 19.5}},
            "by_strategy": {"crypto-momentum": {"trades_7d": 0}, "crypto-oversold-bounce": {"trades_7d": 0}},
        }
        fired, _ = heuristic_crypto_pipeline_silence_alert(stats)
        self.assertFalse(fired)

    def test_no_fire_when_eth_rsi_above_threshold(self):
        stats = {
            "rsi_snapshot": {"BTC/USD": {"today": 15.0}, "ETH/USD": {"today": 26.0}},
            "by_strategy": {"crypto-momentum": {"trades_7d": 0}, "crypto-oversold-bounce": {"trades_7d": 0}},
        }
        fired, _ = heuristic_crypto_pipeline_silence_alert(stats)
        self.assertFalse(fired)

    def test_no_fire_when_crypto_trades_exist(self):
        stats = {
            "rsi_snapshot": {"BTC/USD": {"today": 14.5}, "ETH/USD": {"today": 19.5}},
            "by_strategy": {"crypto-momentum": {"trades_7d": 1}, "crypto-oversold-bounce": {"trades_7d": 0}},
        }
        fired, _ = heuristic_crypto_pipeline_silence_alert(stats)
        self.assertFalse(fired)

    def test_no_fire_with_missing_rsi_snapshot(self):
        stats = {"by_strategy": {}}
        fired, _ = heuristic_crypto_pipeline_silence_alert(stats)
        self.assertFalse(fired)
